// Java 25 exam prep - Packaging artifacts
// Learn: create JARs, link runtimes, and classify unnamed versus automatic modules.
// Compile: javac -d out --module-source-path src $(find src -name "*.java")
String jar = "jar --create --file app.jar -C out .";
String manifestJar = "jar --create --file util.jar --manifest MANIFEST.MF -C util-out .";
String modulePath = "--module-path mods:lib/util.jar"; // util.jar becomes an automatic module here.
String launch = "java " + modulePath + " --module com.example.app/com.example.Main";
String image = "jlink " + modulePath + " --add-modules com.example.app --output image";
String classPath = "java -cp lib/util.jar com.example.Main"; // class-path code is in the unnamed module.
String manifest = "Automatic-Module-Name: com.example.util";
System.out.println(jar);
System.out.println(image);
System.out.println(classPath + " # " + manifest);
